import{_ as t,o as i,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Android App Links","description":"","frontmatter":{"title":"Android App Links","slug":"android-app-links"},"headers":[],"relativePath":"developer-hub/android-app-links.md","filePath":"developer-hub/android-app-links.md"}'),o={name:"developer-hub/android-app-links.md"};function s(r,e,l,d,p,h){return i(),a("div",null,[...e[0]||(e[0]=[n(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch makes it simple to enable Android App Links while greatly improving on them, offering full attribution, supporting edge cases where Android App Links fail, and allowing you to deep link when the user doesn&#39;t have your app installed. Note that Android App Links only work on Android 6+; Branch can handle the rest!</p><h3 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h3><h4 id="_1-generate-signing-certificate-fingerprint" tabindex="-1">1. Generate signing certificate fingerprint <a class="header-anchor" href="#_1-generate-signing-certificate-fingerprint" aria-label="Permalink to &quot;1. Generate signing certificate fingerprint&quot;">​</a></h4><ol><li><p>Start by generating a SHA256 fingerprint of your app&#39;s signing certificate.</p><ol><li>Navigate to your <a href="https://developer.android.com/studio/publish/app-signing#generate-key" target="_blank" rel="noreferrer">keystore</a> file. This is the file that you use to build the debug and production version of your APK file before deploying it.</li><li>Run this command to generate the fingerprint: <code>keytool -list -v -keystore xxxx-example-my-release-key.keystore</code></li><li>You&#39;ll see a value like<br><code>14:6D:E9:83:C5:73:06:50:D8:EE:B9:95:2F:34:FC:64:16:A0:83:42:E6:1D:BE:A8:8A:04:96:B2:3F:CF:44:E5</code><br> come out the other end. Copy this.</li></ol></li><li><p>Now, you’ll enable app links on the Branch dashboard by doing the following:</p><ol><li>Head to the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration</a> page on the Branch dashboard.</li><li>Toggle the <strong>Enable App Links</strong> checkbox in the Android section.</li><li>Paste the copied fingerprint value into the <strong>SHA256 Cert Fingerprints</strong> field that appears. You can insert both your debug and production fingerprints for testing. Simply separate them with a comma.</li><li>Scroll down and click <strong>Save</strong>.</li></ol></li><li><p>Now, add your Intent Filter to Manifest by going to the Link Domain section on the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration</a> page.</p><ol><li>Copy your domain name.</li><li>Choose the <code>Activity</code> you want to open up when a link is clicked. This is typically your <code>SplashActivity</code> or a <code>BaseActivity</code> that all other activities inherit from (and likely the same one you selected in the SDK integration guide.</li><li>Inside your <code>AndroidManifest.xml</code>, locate where the selected <code>Activity</code> is defined.</li><li>Within the <code>Activity</code> definition, insert the intent filter provided below (making sure that <code>xxxx</code> matches the subdomain prefix you&#39;ve been assigned or selected for yourself). Add this as its own separate intent filter.</li><li>If you use a custom domain or subdomain for your Branch Links, you should also add an entry for:</li></ol></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;data android:scheme=&quot;https&quot; android:host=&quot;mycustomdomainorsubdomain&quot; /&gt;</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;intent-filter android:autoVerify=&quot;true&quot;&gt;</span></span>
<span class="line"><span>    &lt;action android:name=&quot;android.intent.action.VIEW&quot; /&gt;</span></span>
<span class="line"><span>    &lt;category android:name=&quot;android.intent.category.DEFAULT&quot; /&gt;</span></span>
<span class="line"><span>    &lt;category android:name=&quot;android.intent.category.BROWSABLE&quot; /&gt;</span></span>
<span class="line"><span>    &lt;data android:scheme=&quot;https&quot; android:host=&quot;xxxx.app.link&quot; /&gt;</span></span>
<span class="line"><span>    &lt;data android:scheme=&quot;https&quot; android:host=&quot;xxxx-alternate.app.link&quot; /&gt;</span></span>
<span class="line"><span>    &lt;data android:scheme=&quot;https&quot; android:host=&quot;xxxx.test-app.link&quot; /&gt;</span></span>
<span class="line"><span>    &lt;data android:scheme=&quot;https&quot; android:host=&quot;xxxx-alternate.test-app.link&quot; /&gt;</span></span>
<span class="line"><span>&lt;/intent-filter&gt;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">Domain Validation</p><p>The system must be able to verify every host specified in a URL intent filters’ data elements against the Digital Asset Links files hosted on the respective web domains. If any verification fails, the app is not verified to be a default handler for any of the URL patterns defined in the app&#39;s intent filters. You can use Google&#39;s <a href="https://developers.google.com/digital-asset-links/tools/generator" target="_blank" rel="noreferrer">Statement List Asset Generator</a> to test your existing statement file.</p></div><h4 id="_2-get-apk-sha256-fingerprints" tabindex="-1">2. Get APK SHA256 Fingerprints <a class="header-anchor" href="#_2-get-apk-sha256-fingerprints" aria-label="Permalink to &quot;2. Get APK SHA256 Fingerprints&quot;">​</a></h4><ol><li>Run: <code>keytool -printcert -jarfile my_app.apk</code> on your APK file.</li></ol><h2 id="faqs" tabindex="-1">FAQs <a class="header-anchor" href="#faqs" aria-label="Permalink to &quot;FAQs&quot;">​</a></h2><details><summary>How do I debug Android App Links?</summary><ol><li><p><strong>Confirm the device browser is NOT the default handler for <em>xx.app.link</em> domain</strong></p><ol><li>Android App Links sets the app as the default handler for a domain (i.e., xx.app.link). If a user clicks a link before App Links is enabled, they’ll have the option to open in browser or in app. If the browser is selected with “always”, that domain will never open the app.</li><li><strong>Reset browser defaults</strong>: Settings → Apps → select the browser → Defaults → “Clear Defaults”</li></ol></li><li><p><strong>If one domain is failing verification, App Links is disabled for every other domain too</strong></p><ol><li>Every <a href="https://developer.android.com/training/app-links/verify-site-associations.html#multi-subdomain" target="_blank" rel="noreferrer">domain &amp; subdomain</a> in Manifest must host a DAL file at: <em>https://</em><em><strong>[domain]</strong></em><em>/.well-known/assetlinks.json</em></li><li>Even if <strong>autoVerify=&quot;true&quot;</strong> is not in all intent filters, <a href="https://developer.android.com/training/app-links/verify-site-associations#request-verify" target="_blank" rel="noreferrer">Android will scrape every domain</a></li><li>Confirm Branch dashboard &amp; all other DAL files contain the correct <a href="https://developers.google.com/digital-asset-links/v1/getting-started" target="_blank" rel="noreferrer">SHA 256 fingerprint</a></li><li>Confirm app’s compileSdkVersion in build.gradle is 23+</li><li>All link domains must be publicly accessible (not behind firewall/vpn) and accessible by Google&#39;s bots</li></ol></li><li><p><strong>Validate App Links :</strong> Install app &gt; connect device to Android Studio &gt; <a href="https://developer.android.com/training/app-links/verify-site-associations.html#check-link-policies" target="_blank" rel="noreferrer"><em>./adb shell dumpsys package d</em></a></p></li></ol><p><em>[Image: 1212]</em></p></details>`,12)])])}const g=t(o,[["render",s]]);export{u as __pageData,g as default};
